console.log(`Seeding ${facilities.length} facilities...`);
let inserted = 0, skipped = 0;
for (const f of facilities) {
  try {
    await conn.execute(
      `INSERT IGNORE INTO facilities (name, country, lat, lon, type, region, importance, description, tags, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())`,
      [f.name, f.country, f.lat, f.lon, f.type, f.region, f.importance, f.description, JSON.stringify(f.tags)]
    );
    inserted++;
    if (inserted % 20 === 0) console.log(`  ${inserted}/${facilities.length} inserted...`);
  } catch (e) {
    skipped++;
  }
}
console.log(`Done: ${inserted} inserted, ${skipped} skipped`);
await conn.end();
